from collections import deque
import sys

def read_grid(h, w):
    grid = []
    for _ in range(h):
        row = list(map(int, sys.stdin.readline().split()))
        grid.append(row)
    return grid

def is_equal(a, b):
    return a == b

def bfs(start, target, h, w):
    visited = set()
    queue = deque()
    queue.append((start, 0))
    visited.add(tuple(map(tuple, start)))

    while queue:
        current, steps = queue.popleft()

        if is_equal(current, target):
            return steps

        # Try all row swaps
        for i in range(h - 1):
            new_grid = [row[:] for row in current]
            new_grid[i], new_grid[i + 1] = new_grid[i + 1], new_grid[i]
            state = tuple(tuple(row) for row in new_grid)
            if state not in visited:
                visited.add(state)
                queue.append((new_grid, steps + 1))

        # Try all column swaps
        for j in range(w - 1):
            new_grid = [row[:] for row in current]
            for row in new_grid:
                row[j], row[j + 1] = row[j + 1], row[j]
            state = tuple(tuple(row) for row in new_grid)
            if state not in visited:
                visited.add(state)
                queue.append((new_grid, steps + 1))

    return -1

def main():
    h, w = map(int, sys.stdin.readline().split())
    grid_a = read_grid(h, w)
    grid_b = read_grid(h, w)

    if not is_equal(grid_a, grid_b):
        print(bfs(grid_a, grid_b, h, w))
    else:
        print(0)

if __name__ == "__main__":
    main()
